namespace sv_884cb16f07e0438f8c0e473348ba595e.Services;

public enum Severity
{
    Info,
    Warning,
    Critical
}

public sealed class NotificationItem
{
    public Guid Id { get; init; } = Guid.NewGuid();
    public required string Title { get; init; }
    public required string Message { get; init; }
    public Severity Severity { get; init; }
    public bool IsRead { get; set; }
    public DateTime Timestamp { get; init; } = DateTime.UtcNow;
}

/// <summary>
/// Scoped per-circuit service that holds notification state and notifies
/// all subscribed components when anything changes.
/// </summary>
public sealed class NotificationHub
{
    private readonly List<NotificationItem> _notifications = new();
    private readonly object _lock = new();

    /// <summary>
    /// Components subscribe to this event to be notified of any state change.
    /// Handlers are invoked synchronously under the lock, so subscribers should
    /// only set a dirty flag and call StateHasChanged via InvokeAsync.
    /// </summary>
    public event Action? OnChange;

    public IReadOnlyList<NotificationItem> GetAll()
    {
        lock (_lock)
        {
            return _notifications.ToList();
        }
    }

    public int GetUnreadCount()
    {
        lock (_lock)
        {
            return _notifications.Count(n => !n.IsRead);
        }
    }

    public void AddNotification(string title, string message, Severity severity)
    {
        lock (_lock)
        {
            _notifications.Add(new NotificationItem
            {
                Title = title,
                Message = message,
                Severity = severity
            });
        }
        NotifySubscribers();
    }

    public void MarkAsRead(Guid id)
    {
        lock (_lock)
        {
            var item = _notifications.FirstOrDefault(n => n.Id == id);
            if (item is not null) item.IsRead = true;
        }
        NotifySubscribers();
    }

    public void MarkAllRead()
    {
        lock (_lock)
        {
            foreach (var n in _notifications) n.IsRead = true;
        }
        NotifySubscribers();
    }

    public void DismissNotification(Guid id)
    {
        lock (_lock)
        {
            _notifications.RemoveAll(n => n.Id == id);
        }
        NotifySubscribers();
    }

    private void NotifySubscribers() => OnChange?.Invoke();
}

namespace sv_884cb16f07e0438f8c0e473348ba595e.Services;

/// <summary>
/// Scoped service that adds a random notification every 15 seconds.
/// Started and stopped by the Dashboard page. Uses a PeriodicTimer
/// so the tick fires on a thread-pool thread; the component that
/// owns this service must marshal UI updates via InvokeAsync.
/// </summary>
public sealed class SimulatorService : IDisposable
{
    private readonly NotificationHub _hub;
    private CancellationTokenSource? _cts;
    private Task? _runningTask;

    private static readonly (string Title, string Message, Severity Severity)[] Templates =
    [
        ("Disk Usage High", "Server disk usage exceeded 85%.", Severity.Warning),
        ("Deployment Succeeded", "v3.2.1 deployed to production.", Severity.Info),
        ("CPU Spike Detected", "CPU usage above 95% for 2 minutes.", Severity.Critical),
        ("New User Signup", "A new user registered on the platform.", Severity.Info),
        ("SSL Certificate Expiring", "Certificate expires in 7 days.", Severity.Warning),
        ("Database Failover", "Primary database is unreachable.", Severity.Critical),
        ("Backup Completed", "Nightly backup finished successfully.", Severity.Info),
        ("Memory Leak Suspected", "Memory usage growing steadily.", Severity.Warning),
    ];

    public SimulatorService(NotificationHub hub)
    {
        _hub = hub;
    }

    public void Start()
    {
        if (_cts is not null) return;
        _cts = new CancellationTokenSource();
        _runningTask = RunAsync(_cts.Token);
    }

    public void Stop()
    {
        _cts?.Cancel();
        _cts?.Dispose();
        _cts = null;
    }

    private async Task RunAsync(CancellationToken ct)
    {
        using var timer = new PeriodicTimer(TimeSpan.FromSeconds(15));
        try
        {
            while (await timer.WaitForNextTickAsync(ct))
            {
                var template = Templates[Random.Shared.Next(Templates.Length)];
                _hub.AddNotification(template.Title, template.Message, template.Severity);
            }
        }
        catch (OperationCanceledException)
        {
            // Expected on dispose/stop
        }
    }

    public void Dispose()
    {
        Stop();
    }
}

@using sv_884cb16f07e0438f8c0e473348ba595e.Services
@inject NotificationHub Hub
@implements IDisposable
@rendermode InteractiveServer

<a href="notifications" class="nav-link notification-bell" title="Notifications">
    <span class="bi bi-bell-nav-menu" aria-hidden="true"></span>
    Notifications
    @if (_unreadCount > 0)
    {
        <span class="badge bg-danger rounded-pill ms-1">@_unreadCount</span>
    }
</a>

@code {
    private int _unreadCount;

    protected override void OnInitialized()
    {
        _unreadCount = Hub.GetUnreadCount();
        Hub.OnChange += HandleChange;
    }

    // OnChange fires from any thread (timer, another component).
    // InvokeAsync marshals the StateHasChanged call onto the
    // Blazor synchronization context for this circuit.
    private async void HandleChange()
    {
        _unreadCount = Hub.GetUnreadCount();
        await InvokeAsync(StateHasChanged);
    }

    public void Dispose()
    {
        Hub.OnChange -= HandleChange;
    }
}

@page "/notifications"
@using sv_884cb16f07e0438f8c0e473348ba595e.Services
@inject NotificationHub Hub
@implements IDisposable
@rendermode InteractiveServer

<PageTitle>Notifications</PageTitle>

<h1>Notifications</h1>

<div class="mb-3">
    <button class="btn btn-primary" @onclick="MarkAllRead">Mark All Read</button>
</div>

@if (!_notifications.Any())
{
    <p class="text-muted">No notifications.</p>
}
else
{
    @foreach (var group in _notifications
        .GroupBy(n => n.Severity)
        .OrderByDescending(g => g.Key))
    {
        <h4 class="mt-4">
            <span class="badge @SeverityBadgeClass(group.Key)">@group.Key</span>
        </h4>

        <ul class="list-group mb-3">
            @foreach (var n in group.OrderByDescending(n => n.Timestamp))
            {
                <li class="list-group-item d-flex justify-content-between align-items-start
                           @(n.IsRead ? "" : "list-group-item-warning")">
                    <div class="ms-2 me-auto">
                        <div class="fw-bold">@n.Title</div>
                        @n.Message
                        <div class="text-muted small">@n.Timestamp.ToString("g")</div>
                    </div>
                    <div class="btn-group btn-group-sm">
                        @if (!n.IsRead)
                        {
                            <button class="btn btn-outline-success" @onclick="() => MarkRead(n.Id)">
                                Mark Read
                            </button>
                        }
                        <button class="btn btn-outline-danger" @onclick="() => Dismiss(n.Id)">
                            Dismiss
                        </button>
                    </div>
                </li>
            }
        </ul>
    }
}

@code {
    private IReadOnlyList<NotificationItem> _notifications = [];

    protected override void OnInitialized()
    {
        _notifications = Hub.GetAll();
        Hub.OnChange += HandleChange;
    }

    private void MarkRead(Guid id) => Hub.MarkAsRead(id);
    private void MarkAllRead() => Hub.MarkAllRead();
    private void Dismiss(Guid id) => Hub.DismissNotification(id);

    private async void HandleChange()
    {
        _notifications = Hub.GetAll();
        await InvokeAsync(StateHasChanged);
    }

    public void Dispose()
    {
        Hub.OnChange -= HandleChange;
    }

    private static string SeverityBadgeClass(Severity s) => s switch
    {
        Severity.Critical => "bg-danger",
        Severity.Warning  => "bg-warning text-dark",
        _                 => "bg-info text-dark"
    };
}

