{"path": "/tmp/sv-884cb16f07e0438f8c0e473348ba595e/Services/SimulatorService.cs", "file_text": "namespace sv_884cb16f07e0438f8c0e473348ba595e.Services;

/// <summary>
/// Scoped service that adds a random notification every 15 seconds.
/// Started and stopped by the Dashboard page. Uses a PeriodicTimer
/// so the tick fires on a thread-pool thread; the component that
/// owns this service must marshal UI updates via InvokeAsync.
/// </summary>
public sealed class SimulatorService : IDisposable
{
    private readonly NotificationHub _hub;
    private CancellationTokenSource? _cts;
    private Task? _runningTask;

    private static readonly (string Title, string Message, Severity Severity)[] Templates =
    [
        ("Disk Usage High", "Server disk usage exceeded 85%.", Severity.Warning),
        ("Deployment Succeeded", "v3.2.1 deployed to production.", Severity.Info),
        ("CPU Spike Detected", "CPU usage above 95% for 2 minutes.", Severity.Critical),
        ("New User Signup", "A new user registered on the platform.", Severity.Info),
        ("SSL Certificate Expiring", "Certificate expires in 7 days.", Severity.Warning),
        ("Database Failover", "Primary database is unreachable.", Severity.Critical),
        ("Backup Completed", "Nightly backup finished successfully.", Severity.Info),
        ("Memory Leak Suspected", "Memory usage growing steadily.", Severity.Warning),
    ];

    public SimulatorService(NotificationHub hub)
    {
        _hub = hub;
    }

    public void Start()
    {
        if (_cts is not null) return;
        _cts = new CancellationTokenSource();
        _runningTask = RunAsync(_cts.Token);
    }

    public void Stop()
    {
        _cts?.Cancel();
        _cts?.Dispose();
        _cts = null;
    }

    private async Task RunAsync(CancellationToken ct)
    {
        using var timer = new PeriodicTimer(TimeSpan.FromSeconds(15));
        try
        {
            while (await timer.WaitForNextTickAsync(ct))
            {
                var template = Templates[Random.Shared.Next(Templates.Length)];
                _hub.AddNotification(template.Title, template.Message, template.Severity);
            }
        }
        catch (OperationCanceledException)
        {
            // Expected on dispose/stop
        }
    }

    public void Dispose()
    {
        Stop();
    }
}
"}

