@page "/notifications"
@using sv_884cb16f07e0438f8c0e473348ba595e.Services
@inject NotificationHub Hub
@implements IDisposable
@rendermode InteractiveServer

<PageTitle>Notifications</PageTitle>

<h1>Notifications</h1>

<div class="mb-3">
    <button class="btn btn-primary" @onclick="MarkAllRead">Mark All Read</button>
</div>

@if (!_notifications.Any())
{
    <p class="text-muted">No notifications.</p>
}
else
{
    @foreach (var group in _notifications
        .GroupBy(n => n.Severity)
        .OrderByDescending(g => g.Key))
    {
        <h4 class="mt-4">
            <span class="badge @SeverityBadgeClass(group.Key)">@group.Key</span>
        </h4>

        <ul class="list-group mb-3">
            @foreach (var n in group.OrderByDescending(n => n.Timestamp))
            {
                <li class="list-group-item d-flex justify-content-between align-items-start
                           @(n.IsRead ? "" : "list-group-item-warning")">
                    <div class="ms-2 me-auto">
                        <div class="fw-bold">@n.Title</div>
                        @n.Message
                        <div class="text-muted small">@n.Timestamp.ToString("g")</div>
                    </div>
                    <div class="btn-group btn-group-sm">
                        @if (!n.IsRead)
                        {
                            <button class="btn btn-outline-success" @onclick="() => MarkRead(n.Id)">
                                Mark Read
                            </button>
                        }
                        <button class="btn btn-outline-danger" @onclick="() => Dismiss(n.Id)">
                            Dismiss
                        </button>
                    </div>
                </li>
            }
        </ul>
    }
}

@code {
    private IReadOnlyList<NotificationItem> _notifications = [];

    protected override void OnInitialized()
    {
        _notifications = Hub.GetAll();
        Hub.OnChange += HandleChange;
    }

    private void MarkRead(Guid id) => Hub.MarkAsRead(id);
    private void MarkAllRead() => Hub.MarkAllRead();
    private void Dismiss(Guid id) => Hub.DismissNotification(id);

    private async void HandleChange()
    {
        _notifications = Hub.GetAll();
        await InvokeAsync(StateHasChanged);
    }

    public void Dispose()
    {
        Hub.OnChange -= HandleChange;
    }

    private static string SeverityBadgeClass(Severity s) => s switch
    {
        Severity.Critical => "bg-danger",
        Severity.Warning  => "bg-warning text-dark",
        _                 => "bg-info text-dark"
    };
}

