@page "/dashboard"
@using sv_884cb16f07e0438f8c0e473348ba595e.Services
@inject NotificationHub Hub
@inject SimulatorService Simulator
@implements IDisposable
@rendermode InteractiveServer

<PageTitle>Dashboard</PageTitle>

<h1>Dashboard</h1>

<p class="text-muted">
    A random notification is added every 15 seconds while this page is open.
</p>

<NotificationSummaryPanel />

@code {
    protected override void OnInitialized()
    {
        Simulator.Start();
    }

    public void Dispose()
    {
        Simulator.Stop();
    }
}

@using sv_884cb16f07e0438f8c0e473348ba595e.Services
@inject NotificationHub Hub
@implements IDisposable

<div class="card">
    <div class="card-header">
        <strong>Recent Unread Notifications</strong>
    </div>
    <div class="card-body">
        @if (!_recent.Any())
        {
            <p class="text-muted mb-0">No unread notifications.</p>
        }
        else
        {
            <ul class="list-group list-group-flush">
                @foreach (var n in _recent)
                {
                    <li class="list-group-item d-flex justify-content-between align-items-center">
                        <div>
                            <span class="badge @SeverityBadgeClass(n.Severity) me-2">@n.Severity</span>
                            <strong>@n.Title</strong>
                            <span class="text-muted small ms-2">@n.Timestamp.ToString("g")</span>
                        </div>
                        <button class="btn btn-sm btn-outline-danger" @onclick="() => Dismiss(n.Id)">
                            Dismiss
                        </button>
                    </li>
                }
            </ul>
        }
    </div>
</div>

@code {
    private List<NotificationItem> _recent = new();

    protected override void OnInitialized()
    {
        RefreshRecent();
        Hub.OnChange += HandleChange;
    }

    private void RefreshRecent()
    {
        _recent = Hub.GetAll()
            .Where(n => !n.IsRead)
            .OrderByDescending(n => n.Timestamp)
            .Take(3)
            .ToList();
    }

    private void Dismiss(Guid id) => Hub.DismissNotification(id);

    private async void HandleChange()
    {
        RefreshRecent();
        await InvokeAsync(StateHasChanged);
    }

    public void Dispose()
    {
        Hub.OnChange -= HandleChange;
    }

    private static string SeverityBadgeClass(Severity s) => s switch
    {
        Severity.Critical => "bg-danger",
        Severity.Warning  => "bg-warning text-dark",
        _                 => "bg-info text-dark"
    };
}

